args.new_str:
window.doNumSpeak = () => {
  stopAll();
  const groups = pad.to_number_groups(val());

  // Generate tone WAV for download/IPFS (separate from play tones)
  lastSpeechWav = pad.to_numbers_wav(val());
  const cid = pad.ipfs_put_dasl(lastSpeechWav, 'audio/wav', 'numbers-station', val());
  const audio = $('speech-audio');
  audio.src = URL.createObjectURL(new Blob([lastSpeechWav], {type:'audio/wav'}));
  audio.style.display = 'block';

  // Speak via SpeechSynthesis
  let text = 'Attention. Attention. Message follows. ';
  for (const c of groups.split(' ')) {
    text += c.split('').join('. ') + '. . ';
  }
  text += 'End of message. End of message.';
  const utt = new SpeechSynthesisUtterance(text);
  utt.rate = 0.7;
  utt.pitch = 0.8;
  window.speechSynthesis.speak(utt);

  set('speech-out', groups + ' → IPFS: ' + cid);
};
window.doSpeechDl = () => {
  if (lastSpeechWav) downloadWav(lastSpeechWav, 'numbers-speech-' + Date.now() + '.wav');
};

