    [130.0, 400.0, 2000.0],  // 6 "ix"   — ih
    [130.0, 500.0, 1800.0],  // 7 "en"   — eh
    [130.0, 500.0, 2100.0],  // 8 "ate"  — ay
    [130.0, 700.0, 1400.0],  // 9 "ine"  — ah
];
const SPEECH_DIGIT_MS: u32 = 400;
const SPEECH_PAUSE_MS: u32 = 100;
const SPEECH_GROUP_MS: u32 = 350;

fn synth_digit(digit: usize) -> Vec<i16> {
    let [f0, f1, f2] = DIGIT_FORMANTS[digit.min(9)];
    let n = (SAMPLE_RATE * SPEECH_DIGIT_MS / 1000) as usize;
    let mut out = Vec::with_capacity(n);
    for i in 0..n {
        let t = i as f32 / SAMPLE_RATE as f32;
        let frac = i as f32 / n as f32;
        // Envelope: 30ms attack, 50ms release
        let env = if frac < 0.075 { frac / 0.075 }
                  else if frac > 0.875 { (1.0 - frac) / 0.125 }
                  else { 1.0 };
        let pi2 = 2.0 * core::f32::consts::PI;
        // Glottal pulse (fundamental) + two formant resonances
        let glottal = (pi2 * f0 * t).sin();
        let s = glottal * 0.3
              + (pi2 * f1 * t).sin() * 0.45
              + (pi2 * f2 * t).sin() * 0.25;
        out.push((s * env * 16000.0) as i16);
    }
    out
}

