/// Formant synthesis for digits 0-9. Each digit gets a distinct vowel sound.
/// [F0 (pitch), F1, F2] — simplified English digit vowels
const DIGIT_FORMANTS: [[f32; 3]; 10] = [
    [130.0, 500.0, 1000.0],  // 0 "oh"   — open-o
    [130.0, 600.0, 1200.0],  // 1 "wun"  — short-u
    [130.0, 300.0, 1900.0],  // 2 "too"  — oo
    [130.0, 400.0, 2200.0],  // 3 "ree"  — ee
    [130.0, 700.0, 1100.0],  // 4 "or"   — open-o
    [130.0, 750.0, 1300.0],  // 5 "ive"  — ah-ee
    [130.0, 400.0, 2000.0],  // 6 "ix"   — ih
    [130.0, 500.0, 1800.0],  // 7 "en"   — eh
    [130.0, 500.0, 2100.0],  // 8 "ate"  — ay
    [130.0, 700.0, 1400.0],  // 9 "ine"  — ah
];
const SPEECH_DIGIT_MS: u32 = 400;
const SPEECH_PAUSE_MS: u32 = 100;
const SPEECH_GROUP_MS: u32 = 350;

fn synth_digit(digit: usize) -> Vec<i16> {
    let [f0, f1, f2] = DIGIT_FORMANTS[digit.min(9)];
    let n = (SAMPLE_RATE * SPEECH_DIGIT_MS / 1000) as usize;
    let mut out = Vec::with_capacity(n);
    for i in 0..n {
        let t = i as f32 / SAMPLE_RATE as f32;
        let frac = i as f32 / n as f32;
        // Envelope: 30ms attack, 50ms release
        let env = if frac < 0.075 { frac / 0.075 }
                  else if frac > 0.875 { (1.0 - frac) / 0.125 }
                  else { 1.0 };
        let pi2 = 2.0 * core::f32::consts::PI;
        // Glottal pulse (fundamental) + two formant resonances
        let glottal = (pi2 * f0 * t).sin();
        let s = glottal * 0.3
              + (pi2 * f1 * t).sin() * 0.45
              + (pi2 * f2 * t).sin() * 0.25;
        out.push((s * env * 16000.0) as i16);
    }
    out
}

fn numbers_speech_synth(data: &[u8]) -> Vec<i16> {
    let dec = bytes_to_decimal(data);
    let pause = vec![0i16; (SAMPLE_RATE * SPEECH_PAUSE_MS / 1000) as usize];
    let group_pause = vec![0i16; (SAMPLE_RATE * SPEECH_GROUP_MS / 1000) as usize];
    let mut out = Vec::new();
    // Preamble: two short 800Hz beeps
    for _ in 0..2 {
        for i in 0..(SAMPLE_RATE / 5) {
            let t = i as f32 / SAMPLE_RATE as f32;
            out.push(((2.0 * core::f32::consts::PI * 800.0 * t).sin() * 12000.0) as i16);
        }
        out.extend(&pause);
    }
    out.extend(&group_pause);
    // Speak digits in groups of 2
    for (i, c) in dec.chars().enumerate() {
        if i > 0 && i % 2 == 0 {
            out.extend(&group_pause);
        }
        let d = c.to_digit(10).unwrap_or(0) as usize;
        out.extend(synth_digit(d));
        out.extend(&pause);
    }
    out
}

