fn ecc_decode(bits: &[u8], num_bytes: usize) -> Vec<u8> {
    let mut out = vec![0u8; num_bytes];
    for i in 0..num_bytes * 8 {
        let start = i * STEGO_REDUNDANCY;
        if start + STEGO_REDUNDANCY > bits.len() { break; }
        let ones: usize = bits[start..start + STEGO_REDUNDANCY].iter().map(|&b| b as usize).sum();
        if ones > STEGO_REDUNDANCY / 2 {
            out[i / 8] |= 1 << (7 - (i % 8));
        }
    }
    out
}

fn stego_encode(data: &[u8], carrier: &[u8], width: u32, height: u32) -> Vec<u8> {
    let total_pixels = (width * height) as usize;
    let capacity = (total_pixels * 3) / STEGO_REDUNDANCY / 8;
    let mut payload = Vec::new();
    let len = data.len().min(capacity.saturating_sub(4)) as u32;
    payload.extend_from_slice(&len.to_be_bytes());
    payload.extend_from_slice(&data[..len as usize]);
    let ecc_bits = ecc_encode(&payload);

    let mut pixels = if carrier.len() == total_pixels * 4 {
        carrier.to_vec()
    } else {
        vec![255u8; total_pixels * 4]
    };

    for (idx, &bit) in ecc_bits.iter().enumerate() {
        let px = idx / 3;
        let ch = idx % 3;
        if px >= total_pixels { break; }
        pixels[px * 4 + ch] = (pixels[px * 4 + ch] & 0xFE) | bit;
    }
    pixels
}

fn stego_decode(pixels: &[u8]) -> Vec<u8> {
    let num_pixels = pixels.len() / 4;
    let mut bits = Vec::with_capacity(num_pixels * 3);
    for i in 0..num_pixels {
        for ch in 0..3usize {
            bits.push(pixels[i * 4 + ch] & 1);
        }
    }
    // Decode length prefix (4 bytes) with ECC
    if bits.len() < 32 * STEGO_REDUNDANCY { return Vec::new(); }
    let len_bytes = ecc_decode(&bits, 4);
    let len = u32::from_be_bytes([len_bytes[0], len_bytes[1], len_bytes[2], len_bytes[3]]) as usize;
    if len > num_pixels || bits.len() < (4 + len) * 8 * STEGO_REDUNDANCY { return Vec::new(); }
    ecc_decode(&bits[32 * STEGO_REDUNDANCY..], len)
}

