    `<div style="border-bottom:1px solid #222;padding:2px">&lt;${t.s}&gt; &lt;${t.p}&gt; "${t.o}"</div>`
  ).join('');
}
window.doAddTriple = () => {
  const cid = triples.add($('t-s').value, $('t-p').value, $('t-o').value);
  set('triple-export', 'Added: ' + cid);
  renderTriples(triples.list());
};
