// -- Local IPFS --
window.doIpfsList = () => {
  const cids = JSON.parse(pad.ipfs_list());
  const icons = {morse:'📡', 'bbs-dtmf':'📞', 'numbers-station':'🔢', 'cassette-kcs':'📼', 'stego-lsb':'🖼', 'text/x-morse':'📡', raw:'📄'};
  // Group by source
  const groups = {};
  const orphans = [];
  cids.forEach(c => {
    const raw = pad.ipfs_meta(c);
    let m = null;
    if (raw) { try { m = JSON.parse(raw); } catch(e) {} }
    const entry = {cid: c, meta: m, raw};
    if (m && m.source) {
      const key = m.source;
      if (!groups[key]) groups[key] = [];
      groups[key].push(entry);
    } else {

    } else {
      orphans.push(entry);
    }
  });
  let html = '';
  for (const [src, entries] of Object.entries(groups)) {
    const srcCid = pad.cid(src);
    const label = src.length > 50 ? src.slice(0,50)+'…' : src;
    html += `<div style="margin:4px 0;padding:4px;border:1px solid #333;border-radius:4px">`;
    html += `<div style="color:#ff0">📝 "${label}" <span style="color:#666">${srcCid.slice(0,16)}…</span></div>`;
    entries.forEach(e => {
      const m = e.meta;
      const icon = icons[m.encoding] || '📦';
      const date = m.created ? new Date(m.created).toLocaleTimeString() : '';
      html += `<div style="padding-left:20px;color:#0f0">↳ ${icon} ${m.encoding} <span style="color:#888">${e.cid.slice(0,16)}…</span> <span style="color:#666">${(m.size/1024).toFixed(1)}KB ${m.mime}</span> <span style="color:#aa0">${date}</span></div>`;
    });
    html += `</div>`;
  }
  orphans.forEach(e => {
    const mime = e.meta ? e.meta.mime || e.raw : (e.raw || '?');
    html += `<div style="color:#888;padding:2px 0">📦 ${e.cid.slice(0,16)}… ${mime}</div>`;
  });
  $('ipfs-list').innerHTML = html;
  set('ipfs-out', `${cids.length} blocks, ${Object.keys(groups).length} sources`);
};
window.doIpfsSize = () => {
  set('ipfs-out', `${(pad.ipfs_size() / 1024).toFixed(1)} KB in local IPFS`);
};
window.doExportTar = () => {
  const tar = pad.export_tar();
  const blob = new Blob([tar], {type: 'application/x-tar'});
  const a = document.createElement('a');
  a.href = URL.createObjectURL(blob);
  a.download = 'erdfa-ipfs-' + Date.now() + '.tar';
  a.click();
  set('ipfs-out', `Exported ${tar.length} bytes`);
};
window.doSyncPastebin = async () => {
  const cids = JSON.parse(pad.ipfs_list());
  let ok = 0;
  for (const cid of cids) {
    const data = pad.ipfs_get(cid);
    if (!data) continue;
    try {
      const form = new FormData();
      form.append('file', new Blob([data]), cid);
      await fetch('/pastebin/upload', {method:'POST', body: form});
      ok++;
    } catch(e) {}
  }
  set('ipfs-out', `Synced ${ok}/${cids.length} blocks to pastebin`);

