window.doStegoDl = () => {
  const canvas = $('stego-canvas');
  if (!canvas.width) return;
  const a = document.createElement('a');
  a.href = canvas.toDataURL('image/png');
  a.download = 'stego-' + Date.now() + '.png';
  a.click();
};
window.doStegoSave = () => {
  const canvas = $('stego-canvas');
  if (!canvas.width) return;
  canvas.toBlob(blob => {
    blob.arrayBuffer().then(buf => {
      const cid = pad.ipfs_put_dasl(new Uint8Array(buf), 'image/png', 'stego-dct', val());
      set('stego-out', 'Saved to IPFS: ' + cid);
    });
  }, 'image/png');
};
window.doStegoLoad = () => {
  const panel = $('ipfs-images');
  panel.style.display = 'flex';
  panel.innerHTML = '';
  const cids = JSON.parse(pad.ipfs_list());
  cids.forEach(cid => {
    const raw = pad.ipfs_meta(cid);
    if (!raw) return;
    let m; try { m = JSON.parse(raw); } catch(e) { return; }
    if (!m.mime || !m.mime.startsWith('image/')) return;
    const data = pad.ipfs_get(cid);
    if (!data) return;
    const blob = new Blob([data], {type: m.mime});
    const url = URL.createObjectURL(blob);
    const img = document.createElement('img');
    img.src = url;
    img.title = `${cid.slice(0,16)}… ${m.encoding || ''} ${(m.size/1024).toFixed(1)}KB`;
    img.style.cssText = 'width:64px;height:64px;object-fit:cover;border:1px solid #333;cursor:pointer';
    img.onclick = () => {
      $('carrier-preview').src = url;
      set('stego-out', 'Carrier: ' + cid.slice(0,24) + '…');
    };
    // Right-click to decode
    img.oncontextmenu = (e) => {
      e.preventDefault();
      const canvas = $('stego-canvas');
      canvas.width = img.naturalWidth; canvas.height = img.naturalHeight;
      const ctx = canvas.getContext('2d');
      ctx.drawImage(img, 0, 0);
      const px = ctx.getImageData(0, 0, canvas.width, canvas.height);
      const decoded = pad.stego_decode(new Uint8Array(px.data.buffer), canvas.width, canvas.height);
      if (decoded) {
        $('input').value = decoded;
        set('stego-out', `Decoded ${decoded.length} chars from ${cid.slice(0,16)}…`);
      } else {
        set('stego-out', 'No hidden data in ' + cid.slice(0,16) + '…');
      }
    };
    panel.appendChild(img);
  });
  // Also show URLs from triples that look like images
  const ts = JSON.parse(triples.list());
  ts.forEach(t => {
    if (/\.(png|jpg|jpeg|gif|webp)$/i.test(t.o) || t.p === 'erdfa:image') {
      const img = document.createElement('img');
      img.src = t.o;
      img.crossOrigin = 'anonymous';
      img.title = t.o;
      img.style.cssText = 'width:64px;height:64px;object-fit:cover;border:1px solid #0ff;cursor:pointer';
      img.onclick = () => {
        $('carrier-preview').src = t.o;
        set('stego-out', 'Carrier from RDF: ' + t.o);
      };
      panel.appendChild(img);
    }
  });
  if (!panel.children.length) panel.innerHTML = '<span style="color:#888">No images in store</span>';
};

