use headless_chrome::{Browser, LaunchOptions};
use std::error::Error;

const ERDFA_URL: &str = "https://solana.solfunmeme.com/erdfa/";

fn main() -> Result<(), Box<dyn Error>> {
    println!("🧪 eRDFa Pad — Headless Browser Tests");
    println!("━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━");

    let browser = Browser::new(LaunchOptions {
        headless: true,
        sandbox: false,
        ..Default::default()
    })?;
    let tab = browser.new_tab()?;

    // 1. Load the page
    println!("\n📄 Test 1: Page loads");
    tab.navigate_to(ERDFA_URL)?;
    tab.wait_until_navigated()?;
    let title = tab.get_title()?;
    assert!(title.contains("eRDFa"), "Title should contain eRDFa, got: {}", title);
    println!("✅ PASS: {}", title);

    // Wait for WASM init
    std::thread::sleep(std::time::Duration::from_secs(3));

    // 2. Type text into input
    println!("\n📝 Test 2: Input text");
    let result = tab.evaluate(r#"
        document.getElementById('input').value = 'Hello stego test!';
        document.getElementById('input').value
    "#, false)?;
    println!("✅ PASS: Input set to {:?}", result.value);

    // 3. Morse encode
    println!("\n📡 Test 3: Morse encode");
    let morse = tab.evaluate(r#"
        doMorseEnc();
        document.getElementById('morse-out').textContent
    "#, false)?;
    let morse_text = morse.value.unwrap_or_default();
    println!("✅ PASS: Morse = {}", morse_text);

    // 4. Numbers station encode (decimal)
    println!("\n🔢 Test 4: Numbers station encode");
    let nums = tab.evaluate(r#"
        doNumEnc();
        document.getElementById('num-groups').textContent
    "#, false)?;
    let nums_text = nums.value.unwrap_or_default();
    println!("✅ PASS: Number groups = {}", nums_text);

    // 5. Stego encode roundtrip
    println!("\n🖼 Test 5: Stego DCT encode");
    let stego_result = tab.evaluate(r#"
        (function() {
            // Wait for carrier image to load
            const carrier = document.getElementById('carrier-preview');
            if (!carrier.complete) return 'carrier not loaded';
            doStegoEnc();
            return document.getElementById('stego-out').textContent;
        })()
    "#, false)?;
    println!("   Encode result: {:?}", stego_result.value);

    // 6. Stego decode roundtrip
    println!("\n🔓 Test 6: Stego DCT decode roundtrip");
    let decoded = tab.evaluate(r#"
        (function() {
            doStegoDec();
            return document.getElementById('input').value;
        })()
    "#, false)?;
    let decoded_text = decoded.value.unwrap_or_default().to_string();
    println!("   Decoded: {:?}", decoded_text);
    if decoded_text.contains("Hello stego test!") {
        println!("✅ PASS: Stego roundtrip successful!");
    } else {
        println!("❌ FAIL: Expected 'Hello stego test!', got {:?}", decoded_text);
    }

    // 7. QR encode
    println!("\n📱 Test 7: QR encode");
    let qr = tab.evaluate(r#"
        document.getElementById('input').value = 'QR test data';
        doQrEnc();
        document.getElementById('b64-out').textContent
    "#, false)?;
    println!("✅ PASS: QR result = {:?}", qr.value);

    // 8. Base64 roundtrip
    println!("\n📦 Test 8: Base64 roundtrip");
    let b64 = tab.evaluate(r#"
        document.getElementById('input').value = 'base64 test';
        doB64Enc();
        const encoded = document.getElementById('b64-out').textContent;
        doB64Dec();
        const decoded = document.getElementById('input').value;
        encoded + ' → ' + decoded
    "#, false)?;
